 2	
 3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 4	import { Text, TextVariants } from '@patternfly/react-core';
 5	
 6	const AffinityDescriptionText: React.FC = () => {
 7	  const { t } = useKubevirtTranslation();
 8	  return (
 9	    <>
10	      <Text className="text-muted" component={TextVariants.p}>
11	        {t(
12	          'Set scheduling requirements and affect the ranking of the Node candidates for scheduling.',
13	        )}
14	      </Text>
15	      <Text className="text-muted" component={TextVariants.p}>
16	        {t('Rules with "Preferred" condition will stack with an "AND" relation between them.')}
17	      </Text>
18	      <Text className="text-muted" component={TextVariants.p}>
19	        {t('Rules with "Required" condition will stack with an "OR" relation between them.')}
20	      </Text>
21	    </>
22	  );
23	};
24	export default AffinityDescriptionText;

